<template>
    <div>
        <div v-show="inputList" id="calDiv">
            <el-row class="salaryStyle">
                <el-col :span="12">
                    <span class="titleSpan">月薪:</span>
                    <el-input v-model="salary"></el-input>
                </el-col>
            </el-row>
            <div v-for="(item,index) in costList" :key="index">
                <el-row>
                    <el-col :span="12">
                        <span class="titleSpan">{{item.costListRow1 + ':'}}</span>
                        <el-input v-model="modelList[item.model1]"></el-input>
                    </el-col>
                    <el-col :span="12">
                        <span class="titleSpan">{{item.costListRow2 + ':'}}</span>
                        <el-input v-model="modelList[item.model2]"></el-input>
                    </el-col>
                </el-row>
            </div>
            <el-button class="goButton" @click="goDetail">查看图表</el-button>
            <el-button class="goButton" @click="goBlog">返回博客</el-button>
        </div>
        <div v-show="detailVis" style="display:flex; flex-direction:row; background-color:#ECF0F1; width:1600px; height:600px; border-radius: 12px;margin:0 auto">
            <div id="echartContainer" style="width:600px; height:640px"></div>
            <div style="margin:200px auto; color:#2C3E50; font-size:36px; font-weight: bold">每个月可以结余{{this.modelList.moneyLeft}}</div>
        </div>
        <el-button v-show="detailVis" class="goButton" @click="back">返回</el-button>
    </div>
</template>

<script>
import echarts from 'echarts'
export default {
    data() {
        return {
            salary: 0,
            costList: [
                {costListRow1:'房租', model1: 'rent',costListRow2:'饮食', model2: 'eating'},
                {costListRow1:'健身', model1: 'bdbing',costListRow2:'通勤', model2: 'roading'},
                {costListRow1:'白条', model1: 'whiteTicket',costListRow2:'其他', model2: 'others'},
            ],
            modelList: {
                rent: 0,
                eating: 0,
                bdbing: 440,
                roading: 220,
                whiteTicket: 0,
                others: 0,
                moneyLeft: 0
            },
            changeKey: {
                rent: '房租',
                eating: '饮食',
                bdbing: '健身',
                roading: '通勤',
                whiteTicket: '白条',
                others: '其他',
                moneyLeft: '结余'
            },
            inputList: true,
            detailVis: false
        }
    },
    methods: {
        goCal () {
            this.modelList.moneyLeft = this.salary
            for (const key in this.modelList) {
                if (this.modelList.hasOwnProperty(key) && key !== 'moneyLeft') {
                    this.modelList.moneyLeft -= parseFloat(this.modelList[key])
                }
            }
        },
        goBlog () {
            this.$router.push({name: 'home'})
        },
        goDetail () {
            for (const key in this.modelList) {
                if (this.modelList.hasOwnProperty(key) && key !== 'whiteTicket' && key !== 'moneyLeft') {
                    if (this.modelList[key] === '0' || this.modelList[key] === 0) {
                        this.$message({
                            message: '还有没填的开销',
                            type: 'warning'
                        });
                        return false
                    }
                }
            }
            this.goCal()
            let myChart = echarts.init(document.getElementById('echartContainer'))
            let echartsTempData = []
            for (const key in this.modelList) {
                if (this.modelList.hasOwnProperty(key)) {
                    if (parseFloat(this.modelList[key]) < 0 && key === 'moneyLeft') {
                        this.$message({
                            message: `您本月结余为${this.modelList[key]},无法制图`,
                            type: 'warning'
                        });
                        return
                    } else if (parseFloat(this.modelList[key]) < 0) {
                        this.$message({
                            message: `您输入的数据有误`,
                            type: 'warning'
                        });
                        return
                    }
                    echartsTempData.push({name:this.changeKey[key],value:this.modelList[key]})
                }
            }
            // 绘制图表
            myChart.setOption({
                title: {
                    text: '学生生源地来源分布图',
                    // x 设置水平安放位置，默认左对齐，可选值：'center' ¦ 'left' ¦ 'right' ¦ {number}（x坐标，单位px）
                    x: 'center',
                    // y 设置垂直安放位置，默认全图顶端，可选值：'top' ¦ 'bottom' ¦ 'center' ¦ {number}（y坐标，单位px）
                    y: 'top',
                    // itemGap设置主副标题纵向间隔，单位px，默认为10，
                    itemGap: 30,
                    // backgroundColor: '#EEE',
                    // 主标题文本样式设置
                    textStyle: {
                        fontSize: 36,
                        fontWeight: 'bolder',
                        color: '#2C3E50'
                    }
                },
                series: {
                    type: 'pie',
                    data: echartsTempData,
                    label: {
                        normal: {
                        position: 'inner',  // 设置标签位置，默认在饼状图外 可选值：'outer' ¦ 'inner（饼状图上）'
                        // formatter: '{a} {b} : {c}个 ({d}%)'   设置标签显示内容 ，默认显示{b}
                        // {a}指series.name  {b}指series.data的name
                        // {c}指series.data的value  {d}%指这一部分占总数的百分比
                        formatter: '{c}'
                        }
                    }
                }
            });
            this.inputList = false
            this.detailVis = true
        },
        back () {
            this.inputList = true
            this.detailVis = false
        }
    },
    mounted() {
        // var myChart = echarts.init(document.getElementById('echartContainer'));
        // // 绘制图表
        // myChart.setOption({
        //     type: 'pie',

        // });
    },
}
</script>

